package main

import "fmt"

type User struct {
    Name string
    Age  int
}

// We accept a POINTER to a User (*User)
func updateAge(u *User, newAge int) {
    // We change the ORIGINAL user's age directly!
    u.Age = newAge
}

func main() {
    player := User{Name: "Bob", Age: 20}

    // We pass the ADDRESS (&) of player, not a heavy copy 
    updateAge(&player, 55)

    fmt.Println(player.Name, "is now", player.Age)
}
